import{_ as o,o as i,c as a,ah as t}from"./chunks/framework.Bi9enVNS.js";const h=JSON.parse('{"title":"Capabilities","description":"","frontmatter":{},"headers":[],"relativePath":"en/intro/capabilities.md","filePath":"en/intro/capabilities.md","lastUpdated":1774205896000}'),l={name:"en/intro/capabilities.md"};function d(r,e,c,n,s,u){return i(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">​</a></h1><p>This page summarizes only what the current implementation already does.</p><h2 id="_1-ingestion-and-integration" tabindex="-1">1. Ingestion and integration <a class="header-anchor" href="#_1-ingestion-and-integration" aria-label="Permalink to &quot;1. Ingestion and integration&quot;">​</a></h2><ul><li>One ingestion entrypoint: <code>POST /v1/logs</code></li><li>Supported content types: <ul><li><code>application/protobuf</code></li><li><code>application/protobuf+json</code></li><li><code>application/json</code></li></ul></li><li>Supported content encodings: <code>identity</code> and <code>gzip</code></li><li>Bearer token authorization with project-scoped access</li><li>Batch idempotency keyed by <code>project + request_id</code></li><li>Record-level rejection, so one batch can partially succeed</li></ul><h2 id="_2-structured-validation" tabindex="-1">2. Structured validation <a class="header-anchor" href="#_2-structured-validation" aria-label="Permalink to &quot;2. Structured validation&quot;">​</a></h2><ul><li>Batch-level validation for <code>request_id</code>, <code>project</code>, <code>environment</code>, and <code>producer.protocol_version</code></li><li>Record-level validation for <code>event_time</code>, <code>severity_number</code>, <code>source</code>, <code>trace_id</code>, <code>span_id</code>, and <code>trace_flags</code></li><li>Default record limit of <code>1000</code> per request</li><li>Default decompressed body limit of <code>1 MiB</code></li></ul><h2 id="_3-normalization-and-modeling" tabindex="-1">3. Normalization and modeling <a class="header-anchor" href="#_3-normalization-and-modeling" aria-label="Permalink to &quot;3. Normalization and modeling&quot;">​</a></h2><ul><li>Merges batch <code>default_source</code> with per-record <code>LogRecord.source</code></li><li>Produces a unified <code>NormalizedLogRecord</code></li><li>Computes <code>source_fingerprint</code> for each accepted record</li><li>Preserves both <code>body_text</code> and <code>body_json</code></li></ul><h2 id="_4-query-apis" tabindex="-1">4. Query APIs <a class="header-anchor" href="#_4-query-apis" aria-label="Permalink to &quot;4. Query APIs&quot;">​</a></h2><ul><li><code>GET /v1/logs/search</code></li><li><code>GET /v1/traces/{trace_id}</code></li><li><code>GET /v1/traces/{trace_id}/timeline</code></li><li><code>GET /v1/traces/{trace_id}/topology</code></li><li><code>GET /v1/sources</code></li></ul><h2 id="_5-frontend-visualization" tabindex="-1">5. Frontend visualization <a class="header-anchor" href="#_5-frontend-visualization" aria-label="Permalink to &quot;5. Frontend visualization&quot;">​</a></h2><ul><li>Logs Explorer for filtering and opening traces</li><li>Trace Workbench for summary cards, topology, timeline lanes, and inspection</li><li>Sources View for <code>source_type -&gt; source_name -&gt; instance_id</code></li><li>Built-in UI i18n in the frontend itself</li></ul><h2 id="_6-examples-and-demo-flow" tabindex="-1">6. Examples and demo flow <a class="header-anchor" href="#_6-examples-and-demo-flow" aria-label="Permalink to &quot;6. Examples and demo flow&quot;">​</a></h2><ul><li>Linear trace example</li><li>Fan-out and join example</li><li>Retry loop example</li><li>Message bus handoff example</li><li><code>make preview</code> / <code>./scripts/dev-preview.sh</code> for an end-to-end local preview</li></ul><h2 id="sources-of-truth" tabindex="-1">Sources of truth <a class="header-anchor" href="#sources-of-truth" aria-label="Permalink to &quot;Sources of truth&quot;">​</a></h2><ul><li><code>README.md</code></li><li><code>docs/protocol.md</code></li><li><code>internal/api/http.go</code></li><li><code>internal/ingest/*.go</code></li><li><code>internal/store/*.go</code></li><li><code>web/src/App.jsx</code></li></ul>',16)])])}const m=o(l,[["render",d]]);export{h as __pageData,m as default};
